+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {end: number, image: boolean, label: string, target: string};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      text = this.convertWikiLinks(text, options);
+    }
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      text = this.convertMarkdownLinks(text, options);
+    }
+    return text;
+  }
+
+  private convertWikiLinks(text: string, options: LinkStyleOptions): string {
+    return text.replace(/(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]+))?\\]\\]/g, (match, bang: string, target: string, display?: string) => {
+      const image = bang === '!';
+      if ((image ? options.imageStyle : options.linkStyle) !== 'markdown') {
+        return match;
+      }
+
+      const label = image && display != null && /^\\d+(?:x\\d+)?$/.test(display) ? target : (display ?? target);
+      return `${image ? '!' : ''}[${label}](${target})`;
+    });
+  }
+
+  private convertMarkdownLinks(text: string, options: LinkStyleOptions): string {
+    let result = '';
+    let index = 0;
+    while (index < text.length) {
+      const parsed = this.parseMarkdownLink(text, index);
+      if (!parsed || (parsed.image ? options.imageStyle : options.linkStyle) !== 'wiki') {
+        result += text[index++];
+        continue;
+      }
+
+      if (parsed.target.includes('://')) {
+        result += text.slice(index, parsed.end);
+        index = parsed.end;
+        continue;
+      }
+
+      const defaultDisplay = this.defaultHeadingDisplay(parsed.target);
+      const display = parsed.image
+        ? (parsed.label === '' || parsed.label === parsed.target ? '' : `|${parsed.label}`)
+        : (parsed.label === parsed.target || parsed.label === defaultDisplay ? '' : `|${parsed.label}`);
+      result += `${parsed.image ? '!' : ''}[[${parsed.target}${display}]]`;
+      index = parsed.end;
+    }
+    return result;
+  }
+
+  private parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+    const image = text[start] === '!' && text[start + 1] === '[';
+    const labelStart = image ? start + 1 : start;
+    if (text[labelStart] !== '[' || this.isEscaped(text, start)) {
+      return null;
+    }
+
+    const labelEnd = this.findBalancedBracket(text, labelStart);
+    if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+      return null;
+    }
+
+    const closingParen = this.findClosingParen(text, labelEnd + 1);
+    if (closingParen === -1) {
+      return null;
+    }
+
+    const rawLabel = text.slice(labelStart + 1, labelEnd);
+    const rawDestination = text.slice(labelEnd + 2, closingParen);
+    if (rawLabel.includes('\
') || rawDestination.includes('\
')) {
+      return null;
+    }
+
+    const target = this.parseDestination(rawDestination);
+    if (target == null) {
+      return null;
+    }
+
+    return {end: closingParen + 1, image, label: this.unescape(rawLabel), target};
+  }
+
+  private findBalancedBracket(text: string, start: number): number {
+    let depth = 0;
+    for (let index = start; index < text.length; index++) {
+      if (this.isEscaped(text, index)) continue;
+      if (text[index] === '[') depth++;
+      if (text[index] === ']' && --depth === 0) return index;
+      if (text[index] === '\
') return -1;
+    }
+    return -1;
+  }
+
+  private findClosingParen(text: string, start: number): number {
+    let depth = 0;
+    let inAngleDestination = false;
+    for (let index = start; index < text.length; index++) {
+      if (this.isEscaped(text, index)) continue;
+      if (text[index] === '\
') return -1;
+      if (text[index] === '<' && depth === 1) inAngleDestination = true;
+      if (text[index] === '>' && inAngleDestination) inAngleDestination = false;
+      if (inAngleDestination) continue;
+      if (text[index] === '(') depth++;
+      if (text[index] === ')' && --depth === 0) return index;
+    }
+    return -1;
+  }
+
+  private parseDestination(value: string): string | null {
+    const trimmed = value.trim();
+    if (trimmed.startsWith('<')) {
+      const end = this.findUnescaped(trimmed, '>', 1);
+      if (end === -1 || trimmed.slice(end + 1).trim() !== '') return null;
+      return this.unescape(trimmed.slice(1, end));
+    }
+
+    // Bare destinations cannot contain unescaped whitespace. This also excludes titles.
+    for (let index = 0; index < value.length; index++) {
+      if (/\\s/.test(value[index]) && !this.isEscaped(value, index)) return null;
+    }
+    return this.unescape(value);
+  }
+
+  private findUnescaped(value: string, character: string, start: number): number {
+    for (let index = start; index < value.length; index++) {
+      if (value[index] === character && !this.isEscaped(value, index)) return index;
+    }
+    return -1;
+  }
+
+  private isEscaped(value: string, index: number): boolean {
+    let backslashes = 0;
+    for (let cursor = index - 1; cursor >= 0 && value[cursor] === '\\\'; cursor--) backslashes++;
+    return backslashes % 2 === 1;
+  }
+
+  private unescape(value: string): string {
+    return value.replace(/\\\\(.)/g, '$1');
+  }
+
+  private defaultHeadingDisplay(target: string): string {
+    const headingIndex = target.indexOf('#');
+    if (headingIndex === -1) return target;
+    const page = target.slice(0, headingIndex);
+    const heading = target.slice(headingIndex + 1);
+    return page === '' ? heading : `${page} > ${heading}`;
+  }
